draftCreate.query:
mutation OrderEditCommitDerivedStatusesDraftCreate($input: DraftOrderInput!) {
  draftOrderCreate(input: $input) {
    draftOrder {
      id
      status
      totalPriceSet {
        shopMoney {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

draftComplete.query:
mutation OrderEditCommitDerivedStatusesDraftComplete($id: ID!, $paymentPending: Boolean) {
  draftOrderComplete(id: $id, paymentPending: $paymentPending) {
    draftOrder {
      id
      status
      order {
        id
        displayFinancialStatus
        displayFulfillmentStatus
        currentTotalPriceSet {
          shopMoney {
            amount
            currencyCode
          }
        }
        transactions {
          kind
          status
          gateway
          amountSet {
            shopMoney {
              amount
              currencyCode
            }
          }
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

begin.query:
mutation OrderEditCommitDerivedStatusesBegin($id: ID!) {
  orderEditBegin(id: $id) {
    calculatedOrder {
      id
      originalOrder {
        id
      }
    }
    userErrors {
      field
      message
    }
  }
}

addCustomItem.query:
mutation OrderEditCommitDerivedStatusesAddCustomItem($id: ID!, $title: String!, $quantity: Int!, $price: MoneyInput!) {
  orderEditAddCustomItem(id: $id, title: $title, quantity: $quantity, price: $price) {
    calculatedOrder {
      id
      totalPriceSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      addedLineItems(first: 5) {
        nodes {
          id
          title
          quantity
        }
      }
    }
    calculatedLineItem {
      id
      title
      quantity
      originalUnitPriceSet {
        shopMoney {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

commit.query:
mutation OrderEditCommitDerivedStatusesCommit($id: ID!, $notifyCustomer: Boolean, $staffNote: String) {
  orderEditCommit(id: $id, notifyCustomer: $notifyCustomer, staffNote: $staffNote) {
    order {
      id
      displayFinancialStatus
      displayFulfillmentStatus
      totalOutstandingSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      totalPriceSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      currentTotalPriceSet {
        shopMoney {
          amount
          currencyCode
        }
      }
    }
    successMessages
    userErrors {
      field
      message
    }
  }
}

