cleanup.query:
#graphql
  mutation OrderEditCommitDerivedStatusesCancel(
    $orderId: ID!
    $reason: OrderCancelReason!
    $notifyCustomer: Boolean!
    $restock: Boolean!
    $refund: Boolean!
  ) {
    orderCancel(
      orderId: $orderId
      reason: $reason
      notifyCustomer: $notifyCustomer
      restock: $restock
      refund: $refund
    ) {
      job {
        id
      }
      userErrors {
        field
        message
      }
    }
  }
